import{_ as e,c as a,o as p,d as t}from"./app.661b9247.js";const u=JSON.parse('{"title":"技术提升","description":"","frontmatter":{},"headers":[{"level":2,"title":"学习参考","slug":"学习参考","link":"#学习参考","children":[]},{"level":2,"title":"前端基建项目：","slug":"前端基建项目","link":"#前端基建项目","children":[]}],"relativePath":"Document/技术提升和职业规划/skillUpgrading.md","lastUpdated":1661228667000}'),r={name:"Document/技术提升和职业规划/skillUpgrading.md"},i=t('<h1 id="技术提升" tabindex="-1">技术提升 <a class="header-anchor" href="#技术提升" aria-hidden="true">#</a></h1><h2 id="学习参考" tabindex="-1">学习参考 <a class="header-anchor" href="#学习参考" aria-hidden="true">#</a></h2><p>第1关 不畏惧,需要什么就学什么</p><p>第⒉关 了解EggJS的基本概念、它的使用场景，看看相关的博客</p><p>第3关 把 EggJS相关的Demo工程/仓库下载到本地，粗略看看目录结构</p><p>第4关 根据官方配套的教程(或市面上免费/付费的教程)，看看如何在命令行中把它runy运行起来</p><p>第5关进一步阅读它的文档，了解各种配置、开关，逐个测试下，完整的掌握它的具体使用方法</p><p>第6关 看看它如何运维发布，找个玩具项目，完整的走一遍从0到1的构建发布过程</p><p>第7关 把它引入到自己的个人/业务项目中，给它编写中间件或者插件</p><p>第8关 把它引入到生产环境中，看看它在真实环境中表现如何，当然可以多做一些性能压测</p><p>第9关 开发和运行一段时间后，看看它有没有什么报错或者Bug，缺陷,尝试修复它</p><p>第10关 如果修复不了，就阅读EggJS源码，找到有问题的位置，分析下这里的调用流程</p><p>第11关 如果是跨领域问题，补充与问题相关的知识（比如网络知识)﹐来寻找理论支撑</p><p>第12关 依然解决不了，就各种Google/issue/阿里云工单/付费请教....不择手段，看如何求助搞定</p><p>第13关 最终依然要到源码层面，逐行Debug，彻底把该流程弄通，问题点和解决方案搞懂</p><p>第14关 提交代码的Fix/Feature之类的分支，向官方社区提交缺陷修复后的代码</p><p>第15关 把这些过程中典型的问题和沉淀的知识,整理成一篇篇的文档，记录下来</p><p>第16关把如上的沉淀，通过大会/公开分享/直播...，亲口讲出来，教给别人，增强自己的理论体系</p><p>第17关 如此反复如上7~16，根据自己的需求，一点点对EggJS做进一步的定制改造/二次开发</p><p>第18关 玩溜了之后，开发一个比EggJS更好的框架，或者自研更符合需求的新的替代方案</p><hr><h2 id="前端基建项目" tabindex="-1">前端基建项目： <a class="header-anchor" href="#前端基建项目" aria-hidden="true">#</a></h2>',22),n=[i];function d(s,l,o,c,_,h){return p(),a("div",null,n)}const m=e(r,[["render",d]]);export{u as __pageData,m as default};
